#include <stdlib.h>
#include <math.h>

int main() {
    FILE *f = fopen("gpt2-124M.ckpt", "rb");
    if (!f) return 1;

    // We will read in chunks and print their mean and std
    long sizes[] = {
        50257 * 768, // wte
        1024 * 768,  // wpe

        // layer 0
        768, // ln_1 g
        768, // ln_1 b
        768 * 2304, // c_attn w
        2304, // c_attn b
        768 * 768, // c_proj w
        768, // c_proj b
        768, // ln_2 g
        768, // ln_2 b
        768 * 3072, // mlp c_fc w
        3072, // mlp c_fc b
        3072 * 768, // mlp c_proj w
        768, // mlp c_proj b
    };

    int n_chunks = sizeof(sizes)/sizeof(sizes[0]);
    float *buf = malloc(50257 * 768 * 4);

    for (int i=0; i<n_chunks; i++) {
        long s = sizes[i];
        fread(buf, sizeof(float), s, f);
        double sum = 0, sum2 = 0;
        for (long j=0; j<s; j++) {
            sum += buf[j];
            sum2 += buf[j]*buf[j];
        }
        double mean = sum / s;
        double std = sqrt(sum2/s - mean*mean);
        printf("Chunk %d, size %ld, mean %f, std %f\n", i, s, mean, std);
    }

    fclose(f);
    return 0;
}
