#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int bs[256];
    int cs[256];
    int n_bs = 0;
    for(int i=33; i<=126; i++) bs[n_bs++] = i;
    for(int i=161; i<=172; i++) bs[n_bs++] = i;
    for(int i=174; i<=255; i++) bs[n_bs++] = i;
    for(int i=0; i<n_bs; i++) cs[i] = bs[i];
    int n = 0;
    for(int b=0; b<256; b++) {
        int found = 0;
        for(int i=0; i<n_bs; i++) if(bs[i] == b) { found = 1; break; }
        if(!found) {
            bs[n_bs] = b;
            cs[n_bs] = 256 + n;
            n_bs++;
            n++;
        }
    }

    // Sort cs to match vocab.json IDs (0 to 255)
    // We want an array token_to_char[256] and byte_to_token[256]
    int sorted_cs[256];
    for(int i=0; i<256; i++) sorted_cs[i] = cs[i];
    // bubble sort
    for(int i=0; i<256; i++) {
        for(int j=i+1; j<256; j++) {
            if(sorted_cs[i] > sorted_cs[j]) {
                int t = sorted_cs[i]; sorted_cs[i] = sorted_cs[j]; sorted_cs[j] = t;
            }
        }
    }

    int byte_to_id[256];
    for(int i=0; i<256; i++) {
        // find sorted_cs index for cs[i]
        for(int j=0; j<256; j++) {
            if(sorted_cs[j] == cs[i]) {
                byte_to_id[bs[i]] = j;
                break;
            }
        }
    }

    printf("Byte 32 (space) id: %d\n", byte_to_id[32]);
    printf("Byte 97 (a) id: %d\n", byte_to_id[97]);

    return 0;
}
