cat << 'EOF' > /app/test_encode.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char *cp_to_utf8(int cp) {
    char *s = malloc(3);
    if(cp <= 127) {
        s[0] = cp; s[1] = 0;
    } else {
        s[0] = 0xC0 | (cp >> 6);
        s[1] = 0x80 | (cp & 0x3F);
        s[2] = 0;
    }
    return s;
}

int main(int argc, char **argv) {
    int bs[256];
    int cs[256];
    int n_bs = 0;
    for(int i=33; i<=126; i++) bs[n_bs++] = i;
    for(int i=161; i<=172; i++) bs[n_bs++] = i;
    for(int i=174; i<=255; i++) bs[n_bs++] = i;
    for(int i=0; i<n_bs; i++) cs[i] = bs[i];
    int n = 0;
    for(int b=0; b<256; b++) {
        int found = 0;
        for(int i=0; i<n_bs; i++) if(bs[i] == b) { found = 1; break; }
        if(!found) { bs[n_bs] = b; cs[n_bs] = 256 + n; n_bs++; n++; }
    }
    int sorted_cs[256];
    for(int i=0; i<256; i++) sorted_cs[i] = cs[i];
    for(int i=0; i<256; i++) {
        for(int j=i+1; j<256; j++) {
            if(sorted_cs[i] > sorted_cs[j]) {
                int t = sorted_cs[i]; sorted_cs[i] = sorted_cs[j]; sorted_cs[j] = t;
            }
        }
    }
    int byte_to_id[256];
    for(int i=0; i<256; i++) {
        for(int j=0; j<256; j++) {
            if(sorted_cs[j] == cs[i]) {
                byte_to_id[bs[i]] = j;
                break;
            }
        }
    }
    char *vocab[50257];
    for(int i=0; i<50257; i++) vocab[i] = NULL;
    for(int i=0; i<256; i++) vocab[i] = cp_to_utf8(sorted_cs[i]);

    FILE *f = fopen("vocab.bpe", "r");
    char line[256];
    fgets(line, sizeof(line), f); // skip header
    for(int i=0; i<50000; i++) {
        if(!fgets(line, sizeof(line), f)) break;
        line[strcspn(line, "\r\n")] = 0;
        char w1[128], w2[128];
        if(sscanf(line, "%s %s", w1, w2) == 2) {
            char *merged = malloc(256);
            sprintf(merged, "%s%s", w1, w2);
            vocab[256+i] = merged;
        }
    }

    char *input = argv[1];
    int *tokens = malloc(strlen(input) * sizeof(int));
    int num_tokens = strlen(input);
    for(int i=0; i<num_tokens; i++) tokens[i] = byte_to_id[(unsigned char)input[i]];

    while(num_tokens > 1) {
        int best_rank = 999999;
