#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>

int bs[256], cs[256], sorted_cs[256], byte_to_id[256];
char *vocab[50257];
int *tok_b[50257], tok_l[50257];

char *cp2utf8(int cp) {
    char *s = malloc(3);
    if(cp <= 127) { s[0] = cp; s[1] = 0; }
    else { s[0] = 0xC0 | (cp >> 6); s[1] = 0x80 | (cp & 0x3F); s[2] = 0; }
    return s;
}

void init_bpe(const char *bpe_path) {
    int n_bs = 0, n = 0;
    for(int i=33; i<=126; i++) bs[n_bs++] = i;
    for(int i=161; i<=172; i++) bs[n_bs++] = i;
    for(int i=174; i<=255; i++) bs[n_bs++] = i;
    for(int i=0; i<n_bs; i++) cs[i] = bs[i];
    for(int b=0; b<256; b++) {
        int f = 0;
        for(int i=0; i<n_bs; i++) if(bs[i] == b) f = 1;
        if(!f) { bs[n_bs] = b; cs[n_bs] = 256 + n++; n_bs++; }
    }
    for(int i=0; i<256; i++) sorted_cs[i] = cs[i];
    for(int i=0; i<256; i++) for(int j=i+1; j<256; j++) 
        if(sorted_cs[i] > sorted_cs[j]) { int t = sorted_cs[i]; sorted_cs[i] = sorted_cs[j]; sorted_cs[j] = t; }
    for(int i=0; i<256; i++) for(int j=0; j<256; j++) 
        if(sorted_cs[j] == cs[i]) { byte_to_id[bs[i]] = j; break; }

    for(int i=0; i<256; i++) vocab[i] = cp2utf8(sorted_cs[i]);
    for(int i=0; i<256; i++) {
        tok_b[i] = malloc(sizeof(int));
        for(int j=0; j<256; j++) if(byte_to_id[j] == i) { tok_b[i][0] = j; break; }
        tok_l[i] = 1;
    }

    FILE *f = fopen(bpe_path, "r");
    char line[512]; fgets(line, sizeof(line), f);
    for(int i=0; i<50000; i++) {
        if(!fgets(line, sizeof(line), f)) break;
        line[strcspn(line, "\r\n")] = 0;
        char w1[256], w2[256];
        if(sscanf(line, "%s %s", w1, w2) == 2) {
            char *m = malloc(512); sprintf(m, "%s%s", w1, w2);
            vocab[256+i] = m;
            int t1 = -1, t2 = -1;
            for(int v=0; v<256+i; v++) {
                if(vocab[v] && !strcmp(vocab[v], w1)) t1 = v;
                if(vocab[v] && !strcmp(vocab[v], w2)) t2 = v;
            }
            if(t1 != -1 && t2 != -1) {
                tok_l[256+i] = tok_l[t1] + tok_l[t2];
                tok_b[256+i] = malloc(tok_l[256+i] * sizeof(int));
                memcpy(tok_b[256+i], tok_b[t1], tok_l[t1]*sizeof(int));
                memcpy(tok_b[256+i]+tok_l[t1], tok_b[t2], tok_l[t2]*sizeof(int));
            }
        }
    }
    fclose(f);
}

int encode(const char *text, int *tokens) {
    int n = strlen(text);
    for(int i=0; i<n; i++) tokens[i] = byte_to_id[(unsigned char)text[i]];
    while(n > 1) {
        int best_r = 999999, best_idx = -1;
        for(int i=0; i<n-1; i++) {
            char m[512]; strcpy(m, vocab[tokens[i]]); strcat(m, vocab[tokens[i+1]]);
            for(int v=256; v<50257; v++) {
                if(vocab[v] && !strcmp(vocab[v], m)) {
                    if(v < best_r) { best_r = v; best_idx = i; }
                    break;
                }
            }
        }
        if(best_idx == -1) break;
        tokens[best_idx] = best_r;
        for(int i=best_idx+1; i<n-1; i++) tokens[i] = tokens[i+1];
        n--;
    }
    return n;
}

void ln(float *x, float *g, float *b, float *out, int d) {
    float m = 0, v = 0;
    for(int i=0; i<d; i++) m += x[i];
    m /= d;
    for(int i=0; i<d; i++) v += (x[i]-m)*(x[i]-m);
    v /= d;
    float s = sqrtf(v + 1e-5f);
    for(int i=0; i<d; i++) out[i] = g[i]*((x[i]-m)/s) + b[i];
}

void matmul(float *x, float *w, float *b, float *out, int d_in, int d_out) {
    for(int j=0; j<d_out; j++) out[j] = b[j];
    for(int i=0; i<d_in; i++) {
        for(int j=0; j<d_out; j++) out[j] += x[i] * w[i*d_out + j];
    }
}

float Kc[12][1024][768];
float Vc[12][1024][768];

int main(int argc, char **argv) {
    init_bpe(argv[2]);
    int tokens[1024];
    int n_tok = encode(argv[3], tokens);

    int fd = open(argv[1], O_RDONLY);
    float *ckpt = mmap(NULL, 124439808 * 4, PROT_READ, MAP_PRIVATE, fd, 0);

    int map_layer[12] = {0, 1, 10, 11, 2, 3, 4, 5, 6, 7, 8, 9};
    int act_to_file[12];
    for(int i=0; i<12; i++) act_to_file[map_layer[i]] = i;

    float *ln_f_b = ckpt + 85054464;
    float *ln_f_g = ckpt + 85055232;
    float *wpe    = ckpt + 85056000;
    float *wte    = ckpt + 85842432;

    for(int pos=0; pos < n_tok + 19; pos++) {
        int token = tokens[pos];
        float x[768];
        for(int i=0; i<768; i++) x[i] = wte[token * 768 + i] + wpe[pos * 768 + i];

        for(int l=0; l<12; l++) {
            long off = act_to_file[l] * 7087872;
            float *c_attn_b = ckpt + off;
            float *c_attn_w = ckpt + off + 2304;
            float *c_proj_b = ckpt + off + 1771776;
            float *c_proj_w = ckpt + off + 1772544;
            float *ln_1_b   = ckpt + off + 2362368;
            float *ln_1_g   = ckpt + off + 2363136;
            float *ln_2_b   = ckpt + off + 2363904;
            float *ln_2_g   = ckpt + off + 2364672;
            float *c_fc_b   = ckpt + off + 2365440;
            float *c_fc_w   = ckpt + off + 2368512;
            float *c_proj_m_b = ckpt + off + 4727808;
            float *c_proj_m_w = ckpt + off + 4728576;

            float x_ln[768], qkv[2304];
            ln(x, ln_1_g, ln_1_b, x_ln, 768);
            matmul(x_ln, c_attn_w, c_attn_b, qkv, 768, 2304);

            for(int i=0; i<768; i++) Kc[l][pos][i] = qkv[768 + i];
            for(int i=0; i<768; i++) Vc[l][pos][i] = qkv[1536 + i];

            float attn_out[768];
            for(int h=0; h<12; h++) {
                float *q_h = qkv + h * 64;
                float scores[1024];
                float max_s = -1e9f;
                for(int t=0; t<=pos; t++) {
                    float *k_h = Kc[l][t] + h * 64;
                    float s = 0;
                    for(int i=0; i<64; i++) s += q_h[i] * k_h[i];
                    scores[t] = s / 8.0f;
                    if(scores[t] > max_s) max_s = scores[t];
                }
                float sum_e = 0;
                for(int t=0; t<=pos; t++) {
                    scores[t] = expf(scores[t] - max_s);
                    sum_e += scores[t];
                }
                for(int i=0; i<64; i++) {
                    float v = 0;
                    for(int t=0; t<=pos; t++) {
                        float *v_h = Vc[l][t] + h * 64;
                        v += (scores[t] / sum_e) * v_h[i];
                    }
                    attn_out[h * 64 + i] = v;
                }
            }
            float proj_out[768];
            matmul(attn_out, c_proj_w, c_proj_b, proj_out, 768, 768);
            for(int i=0; i<768; i++) x[i] += proj_out[i];

            ln(x, ln_2_g, ln_2_b, x_ln, 768);
            float fc_out[3072];
            matmul(x_ln, c_fc_w, c_fc_b, fc_out, 768, 3072);
            for(int i=0; i<3072; i++) {
                float v = fc_out[i];
                fc_out[i] = 0.5f * v * (1.0f + tanhf(0.79788456f * (v + 0.044715f * v * v * v)));
            }
            matmul(fc_out, c_proj_m_w, c_proj_m_b, proj_out, 3072, 768);
            for(int i=0; i<768; i++) x[i] += proj_out[i];
        }

        ln(x, ln_f_g, ln_f_b, x, 768);

        if(pos >= n_tok - 1) {
            float max_l = -1e9f;
            int best_v = 0;
            for(int v=0; v<50257; v++) {
                float l = 0;
                for(int i=0; i<768; i++) l += x[i] * wte[v * 768 + i];
                if(l > max_l) { max_l = l; best_v = v; }
            }
            tokens[pos+1] = best_v;
            for(int i=0; i<tok_l[best_v]; i++) putchar(tok_b[best_v][i]);
            fflush(stdout);
        }
    }
    printf("\n");
    return 0;
}
